  targetBr.setUTCMonth(month - 1);
  if (targetBr.getTime() < brNow.getTime() - 3600*1000) {
    targetBr.setUTCFullYear(targetBr.getUTCFullYear() + 1);
  }
} else {
  const lower = aiResponse.toLowerCase();
  const brWeekday = brNow.getUTCDay();
  const weekdayMap = { 'segunda': 1, 'terça': 2, 'quarta': 3, 'quinta': 4, 'sexta': 5, 'sábado': 6 };
  if (lower.includes('hoje')) {
  } else if (lower.includes('amanhã') || lower.includes('amanha')) {
    targetBr.setUTCDate(targetBr.getUTCDate() + 1);
  } else {
    for (const [kw, wd] of Object.entries(weekdayMap)) {
      if (lower.includes(kw)) {
        let diff = wd - brWeekday;
        if (diff <= 0) diff += 7;
        targetBr.setUTCDate(targetBr.getUTCDate() + diff);
        break;
      }
    }
  }
}
